def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 20):
            base_factor = 1.0
            if j % 4 == 0:
                base_factor = 1.3
            elif j % 5 == 0:
                base_factor = 1.5
            elif j % 2 == 0:
                base_factor = 0.9
            else:
                base_factor = 0.7
            term = base_factor * ((-1)**(j+1)) * (ratio ** j) / (j**1.5)
            score += term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.08 * capacity:
            score *= 1.8
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.25 * capacity:
            score *= 1.0
        else:
            score *= 0.65
        mod_factors = 0
        mods = [3, 5, 7, 11]
        factor_map = {3: 0.06, 5: 0.11, 7: 0.08, 11:0.13}
        for mod in mods:
            if int(capacity) % mod == 0:
                mod_factors += factor_map[mod] * (capacity / (mod*5))
        if mod_factors > 0:
            score -= mod_factors
        else:
            score -= 0.04 * (capacity / 35)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.012 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 1.5 * threshold:
                penalty += 0.15 * k
            elif diff < 3 * threshold:
                penalty -= 0.1 * k
            else:
                penalty -= 0.07 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1, 5):
                if abs((capacity / m) - item) < 0.015 * (capacity / m):
                    score *= (1 + 0.06 * m)
            if int(capacity) % 2 == 0 and int(item*100) % 5 == 0:
                score *= 1.25
            elif int(capacity) % 2 != 0 and int(item*100) % 3 == 0:
                score *= 1.15
        nested_penalty = 0
        factors = [2, 3, 5]
        for a in factors:
            for b in range(1,4):
                val = abs(capacity - item * b * a) / capacity
                if val < 0.01 * b:
                    nested_penalty -= 0.05 * b
                elif val < 0.03 * b:
                    nested_penalty += 0.02 * b
                else:
                    nested_penalty -= 0.01 * b
        score += nested_penalty
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
